# Check all tables referenced in app code vs what exists in DB
python3 << 'PYEOF'
import json, urllib.request, urllib.error, subprocess, os

ANON_KEY = open("/tmp/anon_key.txt").read().strip()
TOKEN = open("/tmp/owner_token.txt").read().strip()
SB = "https://kvclcdjmjghndxsngfzb.supabase.co"

def get(url, headers, timeout=15):
    req = urllib.request.Request(url, headers=headers, method="GET")
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            return resp.status, resp.read().decode()
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode()
    except Exception as e:
        return 0, str(e)

auth = {"apikey": ANON_KEY, "Authorization": f"Bearer {TOKEN}"}

# Get all table names from schema
code, resp = get(f"https://api.ivxholding.com/api/ivx/supabase/schema", {"Authorization": f"Bearer {TOKEN}"})
schema = json.loads(resp)
existing_tables = set()
for r in schema.get("data", {}).get("relations", []):
    if r.get("relation_type") == "table":
        existing_tables.add(r["table_name"])

# Find all .from('table') references in app code
result = subprocess.run(
    ["grep", "-rhoE", "\\.from\\('[a-z_]+'\\)", 
     "/home/user/rork-app/expo/lib/", "/home/user/rork-app/expo/app/", "/home/user/rork-app/expo/src/",
     "/home/user/rork-app/expo/components/", "/home/user/rork-app/expo/hooks/"],
    capture_output=True, text=True, timeout=15
)

referenced_tables = set()
for line in result.stdout.strip().split('\n'):
    if line:
        # Extract table name from .from('table_name')
        table = line.replace(".from('", "").replace("')", "").strip()
        if table:
            referenced_tables.add(table)

missing = referenced_tables - existing_tables
present = referenced_tables & existing_tables

print(f"Tables referenced in app code: {len(referenced_tables)}")
print(f"Tables existing in database: {len(existing_tables)}")
print(f"Tables present (code ∩ db): {len(present)}")
print(f"Tables MISSING (code − db): {len(missing)}")
print()
if missing:
    print("MISSING TABLES (referenced in code but not in database):")
    for t in sorted(missing):
        print(f"  ✗ {t}")
print()
if present:
    print(f"PRESENT TABLES ({len(present)}):")
    for t in sorted(present):
        print(f"  ✓ {t}")
PYEOF

